<?php
namespace App\Http\Controllers\Admin\Content;use App\Domain\Shops\Admin\NpcAdminReadService;use App\Domain\Shops\Admin\NpcAdminService;use App\Http\Controllers\Controller;use App\Http\Requests\Admin\Content\NpcRequest;use App\Models\Npc;use InvalidArgumentException;
final class NpcController extends Controller{public function index(NpcAdminReadService $read){return view('admin.content.npcs.index',['npcs'=>$read->listing()]);}public function create(NpcAdminReadService $read){return view('admin.content.npcs.form',$read->form(new Npc()));}public function store(NpcRequest $request,NpcAdminService $service){return$this->save($request,$service,null,'NPC creado correctamente.');}public function edit(Npc $npc,NpcAdminReadService $read){return view('admin.content.npcs.form',$read->form($npc));}public function update(NpcRequest $request,Npc $npc,NpcAdminService $service){return$this->save($request,$service,$npc,'NPC actualizado correctamente.');}public function activate(Npc $npc,NpcAdminService $service){$service->activate($npc);return back()->with('status','NPC activado correctamente.');}public function deactivate(Npc $npc,NpcAdminService $service){$service->deactivate($npc);return back()->with('status','NPC desactivado correctamente.');}private function save($request,$service,$npc,$message){try{$saved=$service->save($request->validated(),$npc);return redirect()->route('admin.content.npcs.edit',$saved)->with('status',$message);}catch(InvalidArgumentException $e){return back()->withInput()->withErrors(['content'=>$e->getMessage()]);}}}
